import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'user';

export type UserRole = 'admin' | 'sales' | 'sales-support' | 'customer';

export interface SessionUser {
  name: string;
  email: string;
  role: UserRole;
  accountScope?: string; // portal customers are scoped to one account
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;
  private _token = signal<string | null>(localStorage.getItem(TOKEN_KEY));
  private _user = signal<SessionUser | null>(this.readUser());

  readonly isLoggedIn = computed(() => !!this._token());
  readonly token = this._token.asReadonly();
  readonly user = this._user.asReadonly();
  readonly isPortal = computed(() => this._user()?.role === 'customer');
  readonly canSeeMargins = computed(() => {
    const r = this._user()?.role;
    return r === 'admin' || r === 'sales';
  });

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  private readUser(): SessionUser | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as SessionUser) : null;
    } catch {
      return null;
    }
  }

  private persist(token: string, user: SessionUser): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem('token', token);
    localStorage.setItem('access_token', token);
    localStorage.setItem('isAuthenticated', 'true');
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._token.set(token);
    this._user.set(user);
  }

  /** Real backend login (available once the service layer is wired). */
  login(email: string, password: string): Observable<{ user: unknown; token: string }> {
    return this.http
      .post<{ user: unknown; token: string }>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(
        tap((response) => {
          const user: SessionUser = { name: email.split('@')[0], email, role: 'admin' };
          this.persist(response.token, user);
        }),
      );
  }

  /** Client-simulated internal login for the mockup (no backend required). */
  mockLogin(email: string, role: UserRole = 'admin'): void {
    this.persist('mock-internal-token', {
      name: email.split('@')[0] || 'Nexus User',
      email,
      role,
    });
    this.router.navigate(['/dashboard']);
  }

  /** Demo Mode bypass — seeds admin session and jumps to the dashboard. */
  demoLogin(): void {
    this.persist('demo-admin-token', {
      name: 'Demo Admin',
      email: 'demo@nexuspower.com',
      role: 'admin',
    });
    this.router.navigate(['/dashboard']);
  }

  /** Client-simulated signup — first signup becomes admin. */
  signup(name: string, email: string): void {
    this.persist('mock-internal-token', { name, email, role: 'admin' });
    this.router.navigate(['/dashboard']);
  }

  /** Customer portal login — scoped to a single account (QES seeded). */
  portalLogin(email: string): void {
    this.persist('mock-portal-token', {
      name: email.split('@')[0] || 'Portal User',
      email,
      role: 'customer',
      accountScope: 'acc-qes',
    });
    this.router.navigate(['/portal']);
  }

  logout(): void {
    [TOKEN_KEY, 'token', 'access_token', 'isAuthenticated', USER_KEY].forEach((k) =>
      localStorage.removeItem(k),
    );
    this._token.set(null);
    this._user.set(null);
    this.router.navigate(['/login']);
  }
}
